sql:
SELECT state_id, SUM(total_persons) AS total_persons, SUM(total_males) AS total_males
FROM disability_data
GROUP BY state_id;

SELECT SUM(total_persons) AS Total_Disabled_People
FROM disability_data
WHERE district_id = 0;

SELECT COUNT(DISTINCT user_id) AS User_Count
FROM access_logs
WHERE DATE(access_date) = '2022-01-01';

